    def format_missing_nodes(t, limit=5):
        if t["status"] != "MISSING_NODES":
            return None

        nodes = t["missing_nodes"]
        shown = nodes[:limit]
        text = ", ".join(shown)

        if len(nodes) > limit:
            text += ", ..."

        return "missing nodes: " + text

